{"path": "src/performance_test.py", "content": "import time

# Original exponential fibonacci
def fibonacci_original(n):
    if n <= 1:
        return n
    return fibonacci_original(n-1) + fibonacci_original(n-2)

# Optimized fibonacci with memoization
def fibonacci_optimized(n, memo={}):
    if n in memo:
        return memo[n]

    if n <= 1:
        memo[n] = n
        return n

    memo[n] = fibonacci_optimized(n-1, memo) + fibonacci_optimized(n-2, memo)
    return memo[n]

def time_function(func, n, label):
    # Clear memo for fair testing
    if hasattr(func, '__defaults__') and func.__defaults__ and isinstance(func.__defaults__[0], dict):
        func.__defaults__[0].clear()

    start = time.time()
    result = func(n)
    end = time.time()
    print(f"{label}: fibonacci({n}) = {result}, Time: {end - start:.6f} seconds")
    return result

if __name__ == "__main__":
    test_value = 30

    print("Performance comparison:")
    print("-" * 50)

    result_optimized = time_function(fibonacci_optimized, test_value, "Memoized")
    result_original = time_function(fibonacci_original, test_value, "Original")

    print(f"\nResults match: {result_original == result_optimized}")
    print(f"Testing with fibonacci({test_value})")"}
